import React, { useState, useEffect } from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import './buy.css';

function Buy() {
//המערך שיציג את ההזמנות של הלקוח
const [arr_orders, setArrOrders] = useState([]);
//מצב טעינה
const [loading, setLoading] = useState(true);
//שליפת המשתמש הנוכחי מהסטור
const currentUser = useSelector((state) => state.user.currentUser);

//בעת טעינת הקומפוננטה
useEffect(() => {
    //פונקציה לשליפת ההזמנות של הלקוח מהשרת
    const fetchOrders = async () => {
        try {
            //שליפת ההזמנות מהשרת לפי מזהה הלקוח
            const response = await fetch(`http://localhost:8080/api/shoppingApi/getShoppingByCustomerId/${currentUser.pin}`);
            //המרת התגובה לפורמט JSON
            const data = await response.json();
            //עדכון המערך המקומי עם ההזמנות שנשלפו
            setArrOrders(data);
            //במקרה שיש בעיה
        } catch (error) {
            console.error("שגיאה בשליפה", error);
        } finally {
            setLoading(false);
        }
    };
    if (currentUser && currentUser.pin) fetchOrders();
}, [currentUser]);


return (
<div className="orders-container">
            <h1 className="title">היסטוריית הקניות שלי</h1>
            
            {loading ? (
                <p className="status-msg">טוען נתונים מהמערכת...</p>
            ) : arr_orders.length > 0 ? (
                <div className="orders-list">
                    {arr_orders.map((order) => (
                        // ... בתוך ה-map של order.robots
<li key={index} className="robot-item-row">
    <div className="robot-info-text">
        <span className="robot-name">{robot.robotName}</span>
        <span className="robot-count">כמות: {robot.count}</span>
    </div>
    {robot.img && (
        <div className="robot-img-container">
            <img 
                src={"http://localhost:8080/" + robot.img} 
                alt={robot.robotName} 
                className="robot-mini-image" 
            />
        </div>
    )}
</li>
                    ))}
                </div>
            ) : (
                <div className="no-data">
                    <p>לא נמצאו רכישות קודמות.</p>
                </div>
            )}
        </div>
);
}
export default Buy;
